compiler_prompt.required_output_schema:
{
  "task_id": "string",
  "execution_mode": "SCRIPT | AGENT",
  "payload": {
    "python_code": "string (Self-contained logic if mode is SCRIPT)",
    "agent_spec": {
      "role": "string (Specialized Persona)",
      "goal": "string (Specific success criteria for this task)",
      "loop_type": "ReAct",
      "tools": ["list_of_permitted_mcp_tools"],
      "instructions": "string (Tactical execution steps)",
      "output_schema": "JSON definition for the final result"
    }
  }
}
